function FollowupTimeline({ followups }) {
  return (
    <div className="card">
      <h3>Followup Timeline</h3>

      {followups?.map((followup) => (
        <div
          key={followup._id}
          className="timeline-item"
        >
          <p>{followup.note}</p>

          <small>
            Next Followup:{' '}
            {new Date(
              followup.nextFollowup
            ).toLocaleDateString()}
          </small>
        </div>
      ))}
    </div>
  );
}

export default FollowupTimeline;
